#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    long long key;
    int cnt;
    struct Node *next;
} Node;

#define TABLE_SIZE 200003

static Node *table[TABLE_SIZE];
static Node pool[200005];
static int poolPtr;

static unsigned long long hash_ll(long long x) {
    return (unsigned long long)(x ^ (x >> 33));
}

static void clear_table() {
    for (int i = 0; i < TABLE_SIZE; ++i) table[i] = NULL;
    poolPtr = 0;
}

static void add(long long x, int *maxFreq) {
    unsigned long long h = hash_ll(x) % TABLE_SIZE;
    Node *cur = table[h];
    while (cur) {
        if (cur->key == x) {
            cur->cnt++;
            if (cur->cnt > *maxFreq) *maxFreq = cur->cnt;
            return;
        }
        cur = cur->next;
    }
    Node *node = &pool[poolPtr++];
    node->key = x;
    node->cnt = 1;
    node->next = table[h];
    table[h] = node;
    if (1 > *maxFreq) *maxFreq = 1;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        clear_table();
        int maxFreq = 0;
        for (int i = 0; i < N; ++i) {
            long long v;
            scanf("%lld", &v);
            add(v, &maxFreq);
        }
        if (N == 1) {
            printf("0\n");
        } else {
            int keep = maxFreq >= 2 ? maxFreq : 2;
            printf("%d\n", N - keep);
        }
    }
    return 0;
}

