import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        freq = {}
        max_freq = 0
        for _ in range(N):
            v = int(next(it))
            cnt = freq.get(v, 0) + 1
            freq[v] = cnt
            if cnt > max_freq:
                max_freq = cnt
        if N == 1:
            out_lines.append('0')
        else:
            keep = max(max_freq, 2)
            out_lines.append(str(N - keep))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

